/bin/zsh -lc "python -c \"import json, subprocess; meta=json.loads(subprocess.check_output(['cargo','metadata','--format-version','1','--no-deps'], text=True, cwd='.')); rows=[]; 
for pkg in meta['packages']:

    path=pkg['manifest_path'].replace(meta['workspace_root']+'/', '');

    rows.append((pkg['name'], path)) if ('/crates/' in pkg['manifest_path'] and any(dep['name']=='orbit-knowledge' for dep in pkg['dependencies'])) else None
print('\\n'.join(f'{name}\\t{path}' for name, path in sorted(rows))); print(f'Total\\t{len(rows)}')\""

